mapper.select:
/* 회사 목록 조회 */
select * from (
	select 
		@rownum := @rownum + 1 as rnum,
		page_tb.*
	from (
		select 
			site_id as co_idx, user_idx as co_id, site_name as co_name, 
			del_yn, reg_uid, reg_date, mod_uid, mod_date 
		from tb_site
	) page_tb
	,  ( select @rownum := 0 ) r
) f_tb
 
limit #{startNum }, #{pageRowCnt }

/* 회사 목록 건수 조회 */
select 
	count(*) as listCnt 
from (
	select 
		@rownum := @rownum + 1 as rnum,
		page_tb.*
	from (
			select 
				site_id as co_idx, user_idx as co_id, site_name as co_name, 
				del_yn, reg_uid, reg_date, mod_uid, mod_date 
			from tb_site
	) page_tb
	,  ( select @rownum := 0 ) r
) f_tb

/* 그룹 목록 조회 */
select * from (
	select 
		@rownum := @rownum + 1 as rnum,
		page_tb.*
	from (
			select 
				site_grp_idx, user_idx, site_grp_id, site_grp_name, del_yn, reg_uid, reg_date, mod_uid, mod_date 
			from tb_site_group
			where del_yn = 'N'
			order by reg_date
	) page_tb
	,  ( select @rownum := 0 ) r
) f_tb
 
limit #{startNum }, #{pageRowCnt }

/* 그룹 목록 건수 조회 */
select 
	count(*) as listCnt 
from (
	select 
		@rownum := @rownum + 1 as rnum,
		page_tb.*
	from (
			select 
				site_grp_idx, user_idx, site_grp_id, site_grp_name, del_yn, reg_uid, reg_date, mod_uid, mod_date 
			from tb_site_group
			where del_yn = 'N'
			order by reg_date
	) page_tb
	,  ( select @rownum := 0 ) r
) f_tb

/* 사이트 목록 조회 */
select * from (
	select 
		@rownum := @rownum + 1 as rnum,
		page_tb.*
	from (
			select 
				site_id, user_idx, site_name, site_grp_idx, area_type, `time_zone`, 
				local_ems_addr, local_ems_key, del_yn, reg_uid, reg_date, mod_uid, mod_date 
			from tb_site
			where del_yn = 'N'
			order by reg_date
	) page_tb
	,  ( select @rownum := 0 ) r
) f_tb

limit #{startNum }, #{pageRowCnt }

/* 사이트 목록 건수 조회 */
select 
	count(*) as listCnt 
from (
	select 
		@rownum := @rownum + 1 as rnum,
		page_tb.*
	from (
			select 
				site_id, user_idx, site_name, site_grp_idx, area_type, `time_zone`, 
				local_ems_addr, local_ems_key, del_yn, reg_uid, reg_date, mod_uid, mod_date 
			from tb_site
			where del_yn = 'N'
			order by reg_date
	) page_tb
	,  ( select @rownum := 0 ) r
) f_tb

/* 사이트 목록(그룹 내) 조회 */ select site_id, user_idx, site_name, site_grp_idx, area_type, `time_zone`, local_ems_addr, local_ems_key, del_yn, reg_uid, reg_date, mod_uid, mod_date from tb_site where del_yn = 'N'
and site_grp_idx = #{siteGrpIdx }
order by reg_date

/* 사이트 목록(고객사 전체중 특정그룹 제외) 조회 */
select 
	site_id, user_idx, site_name, site_grp_idx, area_type, `time_zone`, 
	local_ems_addr, local_ems_key, del_yn, reg_uid, reg_date, mod_uid, mod_date 
from tb_site
where del_yn = 'N'
and user_idx = #{userIdx }
 
and site_grp_idx != #{siteGrpIdx }

order by reg_date

/* 회사 한건 조회 */
select 
	co_idx, co_id, site_grp_id, co_name, del_yn, reg_uid, reg_date, mod_uid, mod_date 
from tb_company
where del_yn = 'N'
and co_idx = #{coIdx }

/* 그룹 한건 조회 */
select 
	site_grp_idx, user_idx, site_grp_id, site_grp_name, del_yn, reg_uid, reg_date, mod_uid, mod_date 
from tb_site_group
where del_yn = 'N'
and site_grp_idx = #{siteGrpIdx }

mapper.insert:
/* 그룹 등록 */ insert into tb_site_group (
user_idx, /* 사용자식별자 */ site_grp_id, /* 사이트그룹ID */ site_grp_name, /* 사이트그룹명 */ del_yn, reg_uid, reg_date ) values (
#{userIdx }, #{siteGrpId }, #{siteGrpName }, 'N', #{regUid }, now() )

mapper.update:
/* 회사 정보 수정 */ update tb_company set
co_name = #{coName }, /* 회사명 */
co_id = #{coId }, /* 회사ID */
mod_uid = #{modUid }, mod_date = now() where 1=1 and co_idx = #{coIdx }

/* 그룹 정보 수정 */ update tb_site_group set
site_grp_id = #{siteGrpId }, /* 사이트그룹ID */
site_grp_name = #{siteGrpName }, /* 사이트그룹명 */
mod_uid = #{modUid }, mod_date = now() where 1=1 and site_grp_idx = #{siteGrpIdx }
